const items = $input.all();
const e = (items && items[0] && items[0].json) || {};
const exec = e.execution || {};
const err = e.execution && e.execution.error ? e.execution.error : (e.error || {});
const lastNode = (err && err.node && err.node.name) || (exec.lastNodeExecuted) || null;

function safeExcerpt(obj) {
  try {
    const s = JSON.stringify(obj);
    return s && s.length > 2000 ? s.substring(0, 2000) + '...' : s;
  } catch (_) { return null; }
}

return [{ json: {
  workflow_id: (e.workflow && e.workflow.id) || null,
  workflow_name: (e.workflow && e.workflow.name) || null,
  execution_id: exec.id || null,
  node_name: lastNode,
  error_message: (err && (err.message || err.description)) || 'Unknown error',
  error_stack: (err && (err.stack || err.cause && JSON.stringify(err.cause))) || null,
  payload_excerpt: safeExcerpt(err) ? JSON.parse(safeExcerpt(err)) : null
} }];
